import { NgModule } from '@angular/core';
import { Routes, RouterModule } from '@angular/router';

import { RequestSubmittalComponent } from './request-submittal.component';

const routes: Routes = [{ path: '', component: RequestSubmittalComponent }];

@NgModule({
  imports: [RouterModule.forChild(routes)],
  exports: [RouterModule]
})
export class RequestSubmittalRoutingModule { }
